Example (Pydantic v2):

```python
from typing import Any
from pydantic import BaseModel, Field, field_validator, field_serializer

try:
    import numpy as np
except ImportError:  # optional
    np = None

class EmbedRequest(BaseModel):
    embedding: list[float] = Field(..., description="768-d embedding")

    @field_validator("embedding", mode="before")
    @classmethod
    def accept_numpy_and_coerce(cls, v: Any):
        if np is not None and isinstance(v, np.ndarray):
            # ensure 1D
            if v.ndim != 1:
                raise ValueError(f"embedding must be 1D, got shape {v.shape}")
            return v.astype(float).tolist()
        return v

    @field_validator("embedding")
    @classmethod
    def check_len(cls, v: list[float]):
        if len(v) != 768:
            raise ValueError(f"embedding must have length 768, got {len(v)}")
        return v

    @field_serializer("embedding")
    def serialize_embedding(self, v: list[float]):
        # already list[float]; keep explicit to guarantee JSON shape
        return v
```

Key points: accept numpy only in `mode='before'` (pre-coercion), normalize to list[float], then enforce length on the normalized representation so JSON dumps are stable.

Example (Pydantic v2):

```python
from typing import Optional, List
from pydantic import BaseModel, field_validator

ALLOWED_LANGS = {"en", "es"}

class EmbedRequest(BaseModel):
    text: Optional[str] = None
    language: str = "en"
    tags: List[str] = []

    @field_validator("text", mode="before")
    @classmethod
    def normalize_text(cls, v):
        if v is None:
            return None
        v = v.strip()
        return v or None  # empty -> None

    @field_validator("language", mode="before")
    @classmethod
    def normalize_language(cls, v):
        if v is None:
            return "en"
        v = str(v).lower().strip()
        if v not in ALLOWED_LANGS:
            raise ValueError(f"language must be one of {sorted(ALLOWED_LANGS)}")
        return v

    @field_validator("tags", mode="before")
    @classmethod
    def dedupe_tags(cls, v):
        if v is None:
            return []
        seen = set()
        out = []
        for t in v:
            t = str(t)
            if t not in seen:
                seen.add(t)
                out.append(t)
        return out
```

(Any equivalent solution using `model_validator` for cross-field rules is acceptable.)

