class Req(BaseModel):
    model_config = ConfigDict(populate_by_name=True)

    inputs: str = Field(validation_alias=('inputs', 'text'), serialization_alias='inputs')

    @field_validator('inputs', mode='before')
    @classmethod
    def prefer_inputs_over_text(cls, v):
        # When using validation_alias with a tuple, Pydantic will typically pick
        # the first matching key; this validator can be used if you normalize
        # dict inputs yourself. Often not needed if alias order is correct.
        return v
```

If you need explicit precedence when the raw input is a dict:

```python
from pydantic import BaseModel, Field, ConfigDict, model_validator

class Req(BaseModel):
    model_config = ConfigDict(populate_by_name=True)
    inputs: str = Field(..., serialization_alias='inputs')

    @model_validator(mode='before')
    @classmethod
    def normalize_aliases(cls, data):
        if isinstance(data, dict):
            if 'inputs' in data:
                return {**data, 'inputs': data['inputs']}
            if 'text' in data and 'inputs' not in data:
                return {**data, 'inputs': data['text']}
        return data
```

